// Assume: frameBuffer is array of RGBA pixels
// width, height are screen dimensions
// x, y are pixel coordinates
// r, g, b, a are color components (0-255)

PROCEDURE SetPixel(x, y, r, g, b, a)
BEGIN
 IF x < 0 OR x >= width OR y < 0 OR y >= height THEN
 RETURN // Out of bounds check
 ENDIF

 pixelIndex = (y * width) + x

 // Pack RGBA into 32-bit value
 frameBuffer[pixelIndex] = (r << 24) | (g << 16) | (b << 8) | a
END
